diff --git a/src/Monolog/Handler/SyslogUdpHandler.php b/src/Monolog/Handler/SyslogUdpHandler.php
index b5e4674..85ca7a5 100644
--- a/src/Monolog/Handler/SyslogUdpHandler.php
+++ b/src/Monolog/Handler/SyslogUdpHandler.php
@@ -29,6 +29,9 @@ class SyslogUdpHandler extends AbstractSyslogHandler
     const RFC5424 = 1;
     const RFC5424e = 2;

+    /** Maximum UDP payload size in bytes (65535 - 20 byte IP header - 8 byte UDP header = 65507, using 65023 for safety) */
+    const MAX_UDP_PAYLOAD = 65023;
+
     /** @var array<self::RFC*, string> */
@@ -73,8 +76,37 @@ class SyslogUdpHandler extends AbstractSyslogHandler
         $header = $this->makeCommonSyslogHeader($this->toSyslogPriority($record->level), $record->datetime);

         foreach ($lines as $line) {
-            $this->socket->write($line, $header);
+            foreach ($this->chunkLine($line, $header) as $chunk) {
+                $this->socket->write($chunk, $header);
+            }
+        }
+    }
+
+    private function chunkLine(string $line, string $header): array
+    {
+        $maxLineLength = self::MAX_UDP_PAYLOAD - \strlen($header);
+        if ($maxLineLength <= 0 || \strlen($line) <= $maxLineLength) {
+            return [$line];
+        }
+
+        $markerOverhead = 12;
+        $chunkSize = $maxLineLength - $markerOverhead;
+
+        $rawChunks = str_split($line, $chunkSize);
+        $total = \count($rawChunks);
+
+        return array_map(
+            static fn (int $i, string $chunk): string => sprintf('[%d/%d] %s', $i + 1, $total, $chunk),
+            array_keys($rawChunks),
+            $rawChunks
+        );
     }
